import React, { useState } from 'react';
import { auditWebsite } from './services/api';

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Space+Mono:ital,wght@0,400;0,700;1,400&family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;1,9..40,300&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --bg:         #0a0a0f;
    --surface:    #111118;
    --border:     #1e1e2e;
    --border-dim: #161622;
    --accent:     #e8ff47;
    --accent-dim: #c8df3d;
    --text:       #e8e8f0;
    --text-muted: #6b6b8a;
    --text-dim:   #3a3a55;
    --red:        #ff4747;
    --orange:     #ff9547;
    --green:      #47ffa0;
    --mono:       'Space Mono', monospace;
    --sans:       'DM Sans', sans-serif;
    --radius:     6px;
  }

  html { font-size: 15px; }

  body {
    background: var(--bg);
    color: var(--text);
    font-family: var(--sans);
    min-height: 100vh;
    line-height: 1.6;
    -webkit-font-smoothing: antialiased;
  }

  .app {
    max-width: 900px;
    margin: 0 auto;
    padding: 0 24px 80px;
  }

  .header {
    padding: 48px 0 40px;
    border-bottom: 1px solid var(--border);
    margin-bottom: 40px;
  }

  .header-label {
    font-family: var(--mono);
    font-size: 0.7rem;
    letter-spacing: 0.15em;
    color: var(--accent);
    text-transform: uppercase;
    margin-bottom: 12px;
  }

  .header h1 {
    font-family: var(--mono);
    font-size: 2rem;
    font-weight: 700;
    color: var(--text);
    letter-spacing: -0.02em;
    line-height: 1.15;
  }

  .header h1 span { color: var(--accent); }

  .header-sub {
    margin-top: 10px;
    color: var(--text-muted);
    font-size: 0.9rem;
    font-weight: 300;
  }

  .input-section { margin-bottom: 48px; }

  .input-row {
    display: flex;
    gap: 10px;
    align-items: stretch;
  }

  .url-input {
    flex: 1;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 14px 18px;
    color: var(--text);
    font-family: var(--mono);
    font-size: 0.85rem;
    outline: none;
    transition: border-color 0.2s;
  }

  .url-input::placeholder { color: var(--text-dim); }
  .url-input:focus { border-color: var(--accent); }

  .audit-btn {
    background: var(--accent);
    color: #0a0a0f;
    border: none;
    border-radius: var(--radius);
    padding: 14px 28px;
    font-family: var(--mono);
    font-size: 0.8rem;
    font-weight: 700;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    cursor: pointer;
    transition: background 0.15s, transform 0.1s;
    white-space: nowrap;
  }

  .audit-btn:hover:not(:disabled) { background: var(--accent-dim); }
  .audit-btn:active:not(:disabled) { transform: scale(0.98); }
  .audit-btn:disabled { opacity: 0.5; cursor: not-allowed; }

  .error-msg {
    margin-top: 12px;
    padding: 12px 16px;
    background: rgba(255, 71, 71, 0.08);
    border: 1px solid rgba(255, 71, 71, 0.25);
    border-radius: var(--radius);
    color: var(--red);
    font-size: 0.85rem;
    font-family: var(--mono);
  }

  .loading {
    display: flex;
    align-items: center;
    gap: 14px;
    padding: 28px 0;
    color: var(--text-muted);
    font-family: var(--mono);
    font-size: 0.8rem;
  }

  .spinner {
    width: 20px; height: 20px;
    border: 2px solid var(--border);
    border-top-color: var(--accent);
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
    flex-shrink: 0;
  }

  @keyframes spin { to { transform: rotate(360deg); } }

  .section {
    margin-bottom: 32px;
    border: 1px solid var(--border);
    border-radius: var(--radius);
    overflow: hidden;
  }

  .section-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 14px 20px;
    background: var(--surface);
    border-bottom: 1px solid var(--border);
    cursor: pointer;
    user-select: none;
  }

  .section-title {
    font-family: var(--mono);
    font-size: 0.72rem;
    font-weight: 700;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: var(--text-muted);
    display: flex;
    align-items: center;
    gap: 10px;
  }

  .dot { width: 6px; height: 6px; border-radius: 50%; background: var(--accent); flex-shrink: 0; }
  .dot.orange { background: var(--orange); }
  .dot.green  { background: var(--green);  }
  .dot.red    { background: var(--red);    }

  .chevron { font-size: 0.7rem; color: var(--text-dim); transition: transform 0.2s; }
  .chevron.open { transform: rotate(180deg); }

  .section-body { padding: 20px; }

  .metrics-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
    gap: 12px;
  }

  .metric-card {
    background: var(--bg);
    border: 1px solid var(--border-dim);
    border-radius: var(--radius);
    padding: 16px;
  }

  .metric-value {
    font-family: var(--mono);
    font-size: 1.6rem;
    font-weight: 700;
    color: var(--text);
    line-height: 1;
    margin-bottom: 6px;
  }

  .metric-value.warn  { color: var(--orange); }
  .metric-value.bad   { color: var(--red);    }
  .metric-value.good  { color: var(--green);  }

  .metric-label {
    font-size: 0.72rem;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.07em;
    font-family: var(--mono);
  }

  .insights-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
  }

  .insight-card {
    background: var(--bg);
    border: 1px solid var(--border-dim);
    border-radius: var(--radius);
    padding: 16px;
  }

  .insight-card-label {
    font-family: var(--mono);
    font-size: 0.65rem;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: var(--accent);
    margin-bottom: 8px;
  }

  .insight-card p {
    font-size: 0.88rem;
    color: var(--text);
    line-height: 1.65;
    font-weight: 300;
  }

  .rec-list { display: flex; flex-direction: column; gap: 12px; }

  .rec-card {
    background: var(--bg);
    border: 1px solid var(--border-dim);
    border-radius: var(--radius);
    padding: 18px;
    display: grid;
    grid-template-columns: 36px 1fr;
    gap: 14px;
    align-items: start;
  }

  .rec-priority {
    width: 36px; height: 36px;
    border-radius: 50%;
    border: 1px solid var(--border);
    display: flex; align-items: center; justify-content: center;
    font-family: var(--mono);
    font-size: 0.75rem;
    font-weight: 700;
    flex-shrink: 0;
    margin-top: 2px;
  }

  .rec-priority.p1 { border-color: var(--red);    color: var(--red);    }
  .rec-priority.p2 { border-color: var(--orange);  color: var(--orange); }
  .rec-priority.p3 { border-color: var(--accent);  color: var(--accent); }
  .rec-priority.p4 { border-color: var(--green);   color: var(--green);  }
  .rec-priority.p5 { border-color: var(--text-dim);color: var(--text-muted); }

  .rec-title { font-family: var(--mono); font-size: 0.8rem; font-weight: 700; color: var(--text); margin-bottom: 6px; }
  .rec-reasoning { font-size: 0.85rem; color: var(--text-muted); line-height: 1.6; margin-bottom: 8px; font-weight: 300; }
  .rec-action { font-size: 0.82rem; color: var(--accent); font-family: var(--mono); padding: 8px 12px; background: rgba(232, 255, 71, 0.06); border-radius: 4px; border-left: 2px solid var(--accent); }

  .prompt-tabs { display: flex; gap: 2px; margin-bottom: 16px; background: var(--bg); border-radius: var(--radius); padding: 4px; border: 1px solid var(--border-dim); }

  .prompt-tab { flex: 1; padding: 8px; border: none; background: transparent; color: var(--text-muted); font-family: var(--mono); font-size: 0.68rem; letter-spacing: 0.08em; text-transform: uppercase; cursor: pointer; border-radius: 4px; transition: all 0.15s; }
  .prompt-tab.active { background: var(--surface); color: var(--accent); border: 1px solid var(--border); }

  .prompt-code { background: var(--bg); border: 1px solid var(--border-dim); border-radius: var(--radius); padding: 16px; font-family: var(--mono); font-size: 0.75rem; color: var(--text-muted); white-space: pre-wrap; word-break: break-word; line-height: 1.7; max-height: 400px; overflow-y: auto; }

  .log-meta { display: flex; gap: 16px; margin-bottom: 14px; flex-wrap: wrap; }
  .log-meta-item { font-family: var(--mono); font-size: 0.7rem; color: var(--text-muted); padding: 4px 10px; background: var(--bg); border: 1px solid var(--border-dim); border-radius: 100px; }
  .log-meta-item span { color: var(--accent); }

  .audit-meta { display: flex; align-items: center; gap: 16px; padding: 14px 20px; background: rgba(232, 255, 71, 0.04); border: 1px solid rgba(232, 255, 71, 0.15); border-radius: var(--radius); margin-bottom: 32px; flex-wrap: wrap; }
  .audit-meta-url { font-family: var(--mono); font-size: 0.78rem; color: var(--accent); flex: 1; min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  .audit-meta-time { font-family: var(--mono); font-size: 0.72rem; color: var(--text-muted); white-space: nowrap; }
`;

function Section({ title, dotColor, children, defaultOpen = true }) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="section">
      <div className="section-header" onClick={() => setOpen(!open)}>
        <div className="section-title">
          <span className={`dot ${dotColor || ''}`} />
          {title}
        </div>
        <span className={`chevron ${open ? 'open' : ''}`}>▼</span>
      </div>
      {open && <div className="section-body">{children}</div>}
    </div>
  );
}

function MetricCard({ label, value, colorClass }) {
  return (
    <div className="metric-card">
      <div className={`metric-value ${colorClass || ''}`}>{value ?? '—'}</div>
      <div className="metric-label">{label}</div>
    </div>
  );
}

function MetricsDisplay({ metrics }) {
  if (!metrics) return null;
  const altPct = metrics.missingAltPercent;
  const altColor = altPct > 50 ? 'bad' : altPct > 20 ? 'warn' : 'good';
  const h1Color = metrics.h1Count === 0 ? 'bad' : metrics.h1Count > 1 ? 'warn' : '';
  return (
    <Section title="Factual Metrics" defaultOpen={true}>
      <div className="metrics-grid">
        <MetricCard label="Word Count" value={metrics.wordCount?.toLocaleString()} />
        <MetricCard label="H1 Tags" value={metrics.h1Count} colorClass={h1Color} />
        <MetricCard label="H2 Tags" value={metrics.h2Count} />
        <MetricCard label="H3 Tags" value={metrics.h3Count} />
        <MetricCard label="CTAs Found" value={metrics.ctaCount} colorClass={metrics.ctaCount === 0 ? 'bad' : ''} />
        <MetricCard label="Internal Links" value={metrics.internalLinks} />
        <MetricCard label="External Links" value={metrics.externalLinks} />
        <MetricCard label="Images" value={metrics.imageCount} />
        <MetricCard label="Missing Alt Text" value={`${metrics.missingAltCount} (${altPct}%)`} colorClass={altColor} />
        <MetricCard label="Meta Title" value={metrics.metaTitle ? '✓ Present' : '✗ Missing'} colorClass={metrics.metaTitle ? 'good' : 'bad'} />
        <MetricCard label="Meta Description" value={metrics.metaDescription ? '✓ Present' : '✗ Missing'} colorClass={metrics.metaDescription ? 'good' : 'bad'} />
      </div>
      {metrics.ctaSamples && metrics.ctaSamples.length > 0 && (
        <div style={{ marginTop: 16 }}>
          <div style={{ fontFamily: 'var(--mono)', fontSize: '0.68rem', letterSpacing: '0.1em', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: 8 }}>CTA Text Samples</div>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            {metrics.ctaSamples.map((cta, i) => (
              <span key={i} style={{ fontFamily: 'var(--mono)', fontSize: '0.75rem', padding: '4px 10px', background: 'var(--bg)', border: '1px solid var(--border-dim)', borderRadius: 4, color: 'var(--text-muted)' }}>{cta}</span>
            ))}
          </div>
        </div>
      )}
      {(metrics.metaTitle || metrics.metaDescription) && (
        <div style={{ marginTop: 16, padding: 16, background: 'var(--bg)', border: '1px solid var(--border-dim)', borderRadius: 6 }}>
          <div style={{ fontFamily: 'var(--mono)', fontSize: '0.68rem', color: 'var(--text-muted)', letterSpacing: '0.1em', textTransform: 'uppercase', marginBottom: 8 }}>SERP Preview</div>
          {metrics.metaTitle && <div style={{ color: '#6ab0ff', fontSize: '1rem', marginBottom: 4 }}>{metrics.metaTitle}</div>}
          {metrics.metaDescription && <div style={{ color: '#9aa0a6', fontSize: '0.82rem', lineHeight: 1.5 }}>{metrics.metaDescription}</div>}
        </div>
      )}
    </Section>
  );
}

function InsightsDisplay({ ai }) {
  if (!ai) return null;
  const insights = [
    { label: 'SEO Structure', text: ai.seoAnalysis },
    { label: 'Messaging Clarity', text: ai.messagingClarity },
    { label: 'CTA Analysis', text: ai.ctaAnalysis },
    { label: 'Content Depth', text: ai.contentDepth },
    { label: 'UX Concerns', text: ai.uxConcerns },
  ].filter(i => i.text);
  return (
    <Section title="AI Insights" dotColor="orange" defaultOpen={true}>
      <div className="insights-grid">
        {insights.map((ins, i) => (
          <div className="insight-card" key={i}>
            <div className="insight-card-label">{ins.label}</div>
            <p>{ins.text}</p>
          </div>
        ))}
      </div>
    </Section>
  );
}

function Recommendations({ recommendations }) {
  if (!recommendations?.length) return null;
  const priorityClass = (p) => ['p1','p2','p3','p4','p5'][p-1] || 'p5';
  return (
    <Section title="Recommendations" dotColor="green" defaultOpen={true}>
      <div className="rec-list">
        {recommendations.map((rec, i) => (
          <div className="rec-card" key={i}>
            <div className={`rec-priority ${priorityClass(rec.priority)}`}>P{rec.priority}</div>
            <div>
              <div className="rec-title">{rec.title}</div>
              <div className="rec-reasoning">{rec.reasoning}</div>
              <div className="rec-action">→ {rec.action}</div>
            </div>
          </div>
        ))}
      </div>
    </Section>
  );
}

function PromptLogs({ promptLog }) {
  const [activeTab, setActiveTab] = useState('system');
  if (!promptLog) return null;
  const tabs = [
    { id: 'system', label: 'System Prompt', content: promptLog.systemPrompt },
    { id: 'user',   label: 'User Prompt',   content: promptLog.userPrompt },
    { id: 'input',  label: 'Input Data',    content: promptLog.inputData },
    { id: 'output', label: 'Raw Output',    content: promptLog.rawOutput },
  ];
  const active = tabs.find(t => t.id === activeTab);
  return (
    <Section title="Prompt Logs / Reasoning Trace" dotColor="red" defaultOpen={false}>
      <div className="log-meta">
        <div className="log-meta-item">Model: <span>{promptLog.model}</span></div>
        <div className="log-meta-item">~<span>{promptLog.inputTokensEstimate?.toLocaleString()}</span> input tokens</div>
      </div>
      <div className="prompt-tabs">
        {tabs.map(tab => (
          <button key={tab.id} className={`prompt-tab ${activeTab === tab.id ? 'active' : ''}`} onClick={() => setActiveTab(tab.id)}>{tab.label}</button>
        ))}
      </div>
      <pre className="prompt-code">{active?.content || '—'}</pre>
    </Section>
  );
}

export default function App() {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  const handleSubmit = async () => {
    if (!url.trim()) return;
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await auditWebsite(url.trim());
      setResult(data);
    } catch (err) {
      setError(err.message || 'An unexpected error occurred.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <style>{styles}</style>
      <div className="app">
        <header className="header">
          <div className="header-label">Eight25Media · Internal Tool</div>
          <h1>Website <span>Audit</span></h1>
          <p className="header-sub">Scrape any URL · Extract factual metrics · Generate AI insights with Claude</p>
        </header>
        <div className="input-section">
          <div className="input-row">
            <input className="url-input" type="text" value={url} onChange={e => setUrl(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSubmit()} placeholder="https://example.com" disabled={loading} spellCheck={false} />
            <button className="audit-btn" onClick={handleSubmit} disabled={loading || !url.trim()}>{loading ? 'Auditing...' : 'Run Audit →'}</button>
          </div>
          {error && <div className="error-msg">⚠ {error}</div>}
        </div>
        {loading && (
          <div className="loading">
            <div className="spinner" />
            <span>Scraping page → extracting metrics → generating AI insights…</span>
          </div>
        )}
        {result && (
          <>
            <div className="audit-meta">
              <div className="audit-meta-url">✓ {result.url}</div>
              <div className="audit-meta-time">Completed in {(result.processingTimeMs / 1000).toFixed(1)}s</div>
            </div>
            <MetricsDisplay metrics={result.metrics} />
            <InsightsDisplay ai={result.ai} />
            <Recommendations recommendations={result.ai?.recommendations} />
            <PromptLogs promptLog={result.promptLog} />
          </>
        )}
      </div>
    </>
  );
}
